import { useApp } from "../context/AppContext";
import { DAYS, MEAL_TYPES } from "../data/recipes";

export default function PlannerBoard() {
const { state, dispatch } = useApp();

return ( <div> <h2>Meal Planner</h2>


  {DAYS.map(day => (
    <div key={day}>
      <h3>{day}</h3>

      {MEAL_TYPES.map(type => (
        <div key={type}>
          <strong>{type}</strong>

          {state.planner[day][type].map(meal => (
            <div key={meal.id}>
              {meal.name}
              <button
                onClick={() =>
                  dispatch({
                    type: "REMOVE_FROM_PLANNER",
                    payload: {
                      day,
                      mealType: type,
                      recipeId: meal.id
                    }
                  })
                }
              >
                ❌
              </button>
            </div>
          ))}
        </div>
      ))}
    </div>
  ))}
</div>


);
}
